diff --git a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
index a4831ea7c11f..e688370386df 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -2889,6 +2889,20 @@ void VPPredInstPHIRecipe::execute(VPTransformState &State) {
       cast<Instruction>(State.get(getOperand(0), *State.Lane));
   BasicBlock *PredicatedBB = ScalarPredInst->getParent();
   BasicBlock *PredicatingBB = PredicatedBB->getSinglePredecessor();
+  // If the instruction is not in a predicated block (i.e., the block doesn't
+  // have a single predecessor), then we don't need to create a phi node.
+  // This can happen when a predicated instruction is optimized away and
+  // replaced with a non-predicated value.
+  if (!PredicatingBB) {
+    // The instruction is not predicated, so no phi is needed.
+    // Just forward the value from the operand.
+    if (State.hasVectorValue(getOperand(0))) {
+      State.set(this, State.get(getOperand(0)));
+    } else {
+      State.set(this, ScalarPredInst, *State.Lane);
+    }
+    return;
+  }
   assert(PredicatingBB && "Predicated block has no single predecessor.");
   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
          "operand must be VPReplicateRecipe");
diff --git a/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
index 5b42a9056b69..a00fd0e1c758 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
@@ -1022,6 +1022,13 @@ static void simplifyRecipe(VPRecipeBase &R, VPTypeAnalysis &TypeInfo) {
       return;
     if (auto *C = dyn_cast<Constant>(Op->getLiveInIRValue()))
       PredPHI->replaceAllUsesWith(Plan->getOrAddLiveIn(C));
+    // If the operand is not a VPReplicateRecipe, the VPPredInstPHIRecipe
+    // shouldn't exist. This can happen when a predicated instruction is
+    // optimized away. Remove the recipe.
+    if (!isa<VPReplicateRecipe>(Op)) {
+      PredPHI->replaceAllUsesWith(Op);
+      PredPHI->eraseFromParent();
+    }
   }

   VPValue *A;

